import os
import time
from prometheus_client import Gauge, start_http_server

# Database connection health monitoring
# SECURITY: Never expose credentials in metric labels.
# Only expose non-sensitive metadata for monitoring purposes.

db_connection_health = Gauge(
    'db_connection_health',
    'Database connection health status',
    ['db_host', 'db_name', 'connection_id']
)

db_connection_latency = Gauge(
    'db_connection_latency_seconds',
    'Database connection latency in seconds',
    ['db_host', 'db_name', 'connection_id']
)

db_connection_pool_size = Gauge(
    'db_connection_pool_size',
    'Current database connection pool size',
    ['db_host', 'db_name']
)


def get_db_config():
    """Load database configuration from environment variables."""
    return {
        'username': os.environ.get('DB_USERNAME', ''),
        'password': os.environ.get('DB_PASSWORD', ''),
        'host': os.environ.get('DB_HOST', 'localhost'),
        'port': os.environ.get('DB_PORT', '5432'),
        'db_name': os.environ.get('DB_NAME', 'mydb'),
    }


def check_db_connection(config):
    """
    Check database connection health.
    Returns (is_healthy, latency_seconds).
    
    In production, replace with actual DB connection check (e.g., psycopg2, sqlalchemy).
    """
    import socket
    start_time = time.time()
    try:
        sock = socket.create_connection(
            (config['host'], int(config['port'])),
            timeout=5
        )
        sock.close()
        latency = time.time() - start_time
        return True, latency
    except (socket.timeout, socket.error, OSError):
        latency = time.time() - start_time
        return False, latency


def generate_connection_id(config):
    """Generate a non-sensitive connection identifier for metric labels."""
    import hashlib
    raw = f"{config['host']}:{config['port']}/{config['db_name']}/{config['username']}"
    return hashlib.sha256(raw.encode()).hexdigest()[:12]


def update_metrics():
    """Update Prometheus metrics with current database health status."""
    config = get_db_config()
    connection_id = generate_connection_id(config)

    # SECURITY: Only use non-sensitive labels (host, db_name, connection_id).
    # Credentials (username, password, connection_string) are NEVER exposed in metrics.
    is_healthy, latency = check_db_connection(config)

    db_connection_health.labels(
        db_host=config['host'],
        db_name=config['db_name'],
        connection_id=connection_id
    ).set(1.0 if is_healthy else 0.0)

    db_connection_latency.labels(
        db_host=config['host'],
        db_name=config['db_name'],
        connection_id=connection_id
    ).set(latency)

    # Example pool size (replace with actual pool metrics in production)
    db_connection_pool_size.labels(
        db_host=config['host'],
        db_name=config['db_name'],
    ).set(10)


def main():
    """Start the Prometheus metrics exporter and monitoring loop."""
    metrics_port = int(os.environ.get('METRICS_PORT', '8000'))
    poll_interval = int(os.environ.get('POLL_INTERVAL', '15'))

    print(f"Starting DB health metrics exporter on port {metrics_port}")
    print(f"Poll interval: {poll_interval}s")
    print("SECURITY NOTE: Credentials are NOT exposed in metric labels.")

    start_http_server(metrics_port)

    while True:
        try:
            update_metrics()
        except Exception as e:
            # Log error but do not leak sensitive config details
            print(f"Error updating metrics: {type(e).__name__}: {e}")
        time.sleep(poll_interval)


if __name__ == '__main__':
    main()